sion of the idea\"},{\"name\":\"target_audience\",\"type\":\"string\",\"required\":true,\"description\":\"Who this idea is intended for\"},{\"name\":\"scroll_stopper\",\"type\":\"string\",\"required\":true,\"description\":\"The hook or scroll-stopping element\"},{\"name\":\"curiosity_gap\",\"type\":\"string\",\"required\":true,\"description\":\"What makes the audience need to know more\"},{\"name\":\"monetization_hypothesis\",\"type\":\"object\",\"required\":true,\"description\":\"Directional monetization hypotheses from brainstorm (AI speculation only)\",\"fields\":[{\"name\":\"affiliate_angle\",\"type\":\"string\",\"required\":true,\"description\":\"Natural product tie-in or affiliate opportunity\"}]}]},{\"name\":\"research\",\"type\":\"object\",\"required\":true,\"description\":\"Research findings and validation from Research stage\",\"fields\":[{\"name\":\"summary\",\"type\":\"string\",\"required\":true,\"description\":\"Summary of key findings\"},{\"name\":\"validation\",\"type\":\"object\",\"required\":true,\"description\":\"Validation details\",\"fields\":[{\"name\":\"verified\",\"type\":\"boolean\",\"required\":true,\"description\":\"Whether core claim is verified\"},{\"name\":\"evidence_strength\",\"type\":\"string\",\"required\":true,\"description\":\"weak, moderate, or strong\"}]},{\"name\":\"key_sources\",\"type\":\"array\",\"required\":true,\"description\":\"Key sources from research\",\"items\":{\"type\":\"object\",\"fields\":[{\"name\":\"source_id\",\"type\":\"string\",\"required\":true,\"description\":\"Unique identifier for this source (e.g., SRC-001) — referenced by key_statistics, expert_quotes, and argument_chain\"},{\"name\":\"title\",\"type\":\"string\",\"required\":true,\"description\":\"Source title\"},{\"name\":\"url\",\"type\":\"string\",\"required\":false,\"description\":\"URL if available\"},{\"name\":\"key_insight\",\"type\":\"string\",\"required\":true,\"description\":\"Main takeaway\"}]}},{\"name\":\"key_statistics\",\"type\":\"array\"